const STORE_NAMES=["Walmart Phoenix AZ","Sam's Club Phoenix AZ","Walmart Tempe AZ","Sam's Club Tempe AZ","Walmart Glendale AZ","Walmart Peoria AZ","Walmart Central Phoenix"];
function timeToMin(t){const m=t.match(/(\d+):(\d+) (AM|PM)/);let h=parseInt(m[1],10)%12;if(m[3]==="PM")h+=12;return h*60+parseInt(m[2],10);}
function tripsForDate(dateObj){
  const key=dateObj.getFullYear()+"-"+String(dateObj.getMonth()+1).padStart(2,"0")+"-"+String(dateObj.getDate()).padStart(2,"0");
  const real=[];
  TRIPS.forEach((t,idx)=>{if(t.dayDate===key)real.push({...t,idx});});
  if(real.length>0){
    real.sort((a,b)=>timeToMin(b.time)-timeToMin(a.time));
    return real;
  }
  // No real trips recorded for this date (older history) — synthesize a consistent breakdown
  const total=+(DAILY_EARNINGS[key]||0);
  if(total<=0)return [];
  const seed=dateObj.getTime();
  const rng=(i)=>{const x=Math.sin(seed/1000000+i*13.37)*43758.5453;return x-Math.floor(x);};
  const n=2+Math.floor(rng(0)*3); // 2-4 trips
  const raw=Array.from({length:n},(_,i)=>0.15+rng(i+1)*0.85);
  const rawSum=raw.reduce((a,b)=>a+b,0);
  const amts=raw.map(r=>+((r/rawSum)*total).toFixed(2));
  let diff=+(total-amts.reduce((a,b)=>a+b,0)).toFixed(2);
  amts[0]=+(amts[0]+diff).toFixed(2);
  const hours=[19,17,15,12,10].slice(0,n).sort((a,b)=>b-a);
  const dateLabel=MO[dateObj.getMonth()]+". "+dateObj.getDate();
  return amts.map((amt,i)=>{
    const h24=hours[i]-Math.floor(rng(i+5)*2);
    const min=Math.floor(rng(i+9)*59);
    const h12=((h24+11)%12)+1;
    const ampm=h24>=12?"PM":"AM";
    const time=h12+":"+String(min).padStart(2,"0")+" "+ampm;
    return {id:"TRP-"+(10000+Math.floor(rng(i+2)*89999)),orders:1+Math.floor(rng(i+3)*3),amt:"$"+amt.toFixed(2),store:STORE_NAMES[Math.floor(rng(i+4)*STORE_NAMES.length)],date:dateLabel,time,miles:(2+rng(i+6)*10).toFixed(1),dayDate:key,idx:null};
  });
}
