function getWeeks(){
  const weeks=[];let d=new Date(2026,1,16);
  while(d<=CWS){
    const key=isoKey(d),end=addD(d,6),isCW=d.getTime()===CWS.getTime();
    const amt=isCW?118.32:(EXACT[key]||parseFloat((480+Math.random()*420).toFixed(2)));
    weeks.push({s:new Date(d),e:new Date(end),amt,isCW});
    d=addD(d,7);
  }
  return weeks.reverse();
}

// Returns the exact same "Incentive Programs" dollar figure shown in the weekly Earnings breakdown for a given week.
function weeklyIncentive(week){
  if(week.isCW)return 0;
  if(isoKey(week.s)==="2026-06-15")return 9.00;
  const total=week.amt;
  const te=+(total*0.77).toFixed(2);
  const tips=+(total*0.195).toFixed(2);
  return +(total-te-tips).toFixed(2);
}

function buildIncentiveHistory(){
  const weeks=getWeeks();
  const entries=[];
  weeks.forEach(week=>{
    const inc=weeklyIncentive(week);
    if(inc<=0)return;
    const seed=week.s.getTime();
    const rng=(i)=>{const x=Math.sin(seed/1000000+i*7.919)*43758.5453;return x-Math.floor(x);};
    const storeType=rng(1)<0.5?"Sam's Club":"Walmart";
    const storeIdNum=4000+Math.floor(rng(2)*999);
    const fulfil=["Curbside Pickup","In-Store Shopping","Delivery from Store"][Math.floor(rng(3)*3)];
    const idChars="abcdefghijklmnopqrstuvwxyz0123456789";
    let incId="";
    for(let c=0;c<9;c++)incId+=idChars[Math.floor(rng(10+c)*idChars.length)];
    entries.push({
      amt:inc,
      weekStart:week.s,
      weekEnd:week.e,
      eligibleZone:STORE_NAMES[Math.floor(rng(4)*STORE_NAMES.length)]+".",
      storeId:storeType+" #"+storeIdNum+"..",
      fulfillment:fulfil,
      incentiveId:incId,
    });
  });
  entries.sort((a,b)=>b.weekStart-a.weekStart);
  return entries;
}
const INCENTIVE_HISTORY=buildIncentiveHistory();

