function Hdr({title,onBack,onClose,onHelp,bg=BLUE}){
  return <div style={{background:bg,padding:"52px 16px 14px",display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0}}>
    {onBack?<div onClick={onBack} style={{color:"#fff",fontSize:28,cursor:"pointer",width:30,fontWeight:200}}>‹</div>:onClose?<div onClick={onClose} style={{color:"#fff",fontSize:22,cursor:"pointer",width:30}}>✕</div>:<div style={{width:30}}/>}
    <div style={{color:"#fff",fontSize:17,fontWeight:600,flex:1,textAlign:"center"}}>{title}</div>
    {onHelp?<div onClick={onHelp} style={{width:24,height:24,borderRadius:"50%",border:"2px solid rgba(255,255,255,0.8)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:700,color:"#fff",cursor:"pointer"}}>?</div>:<div style={{width:30}}/>}
  </div>;
}

function Spark({size=18,color="#FFC200"}){
  const c=size/2,r2=size*0.44;
  const petals=[0,60,120,180,240,300].map(deg=>{
    const a=(deg-90)*Math.PI/180,a1=(deg-102)*Math.PI/180,a2=(deg-78)*Math.PI/180;
    const tx=(c+Math.cos(a)*r2).toFixed(1),ty=(c+Math.sin(a)*r2).toFixed(1);
    const bx1=(c+Math.cos(a1)*size*0.13).toFixed(1),by1=(c+Math.sin(a1)*size*0.13).toFixed(1);
    const bx2=(c+Math.cos(a2)*size*0.13).toFixed(1),by2=(c+Math.sin(a2)*size*0.13).toFixed(1);
    return "M"+c+","+c+" L"+bx1+","+by1+" L"+tx+","+ty+" L"+bx2+","+by2+" Z";
  });
  return <svg width={size} height={size} viewBox={"0 0 "+size+" "+size}>{petals.map((p,i)=><path key={i} d={p} fill={color}/>)}<circle cx={c} cy={c} r={size*0.12} fill={color}/></svg>;
}

