function LiveMap({lat,lng,zoom=13,markers=[]}){
  const containerRef=useRef(null);
  const mapRef=useRef(null);
  useEffect(()=>{
    let cancelled=false;
    function init(){
      if(cancelled||!containerRef.current||mapRef.current||!window.L)return;
      const map=window.L.map(containerRef.current,{zoomControl:true});
      window.L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{
        maxZoom:19,
        attribution:'&copy; OpenStreetMap contributors'
      }).addTo(map);
      window.L.marker([lat,lng]).addTo(map);
      const allPoints=[[lat,lng]];
      markers.forEach(m=>{
        const icon=window.L.divIcon({
          className:"",
          html:`<div style="width:28px;height:28px;border-radius:50%;background:${m.color};border:2.5px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.35);display:flex;align-items:center;justify-content:center;">${m.icon}</div>`,
          iconSize:[28,28],
          iconAnchor:[14,14]
        });
        window.L.marker([m.lat,m.lng],{icon}).addTo(map).bindPopup(m.name);
        allPoints.push([m.lat,m.lng]);
      });
      if(allPoints.length>1){
        map.fitBounds(window.L.latLngBounds(allPoints),{padding:[28,28]});
      }else{
        map.setView([lat,lng],zoom);
      }
      mapRef.current=map;
    }
    if(window.L){
      init();
    }else{
      if(!document.getElementById("leaflet-css")){
        const link=document.createElement("link");
        link.id="leaflet-css";link.rel="stylesheet";
        link.href="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.css";
        document.head.appendChild(link);
      }
      let script=document.getElementById("leaflet-js");
      if(!script){
        script=document.createElement("script");
        script.id="leaflet-js";
        script.src="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.js";
        document.body.appendChild(script);
      }
      script.addEventListener("load",init);
      if(window.L)init();
    }
    return ()=>{
      cancelled=true;
      if(mapRef.current){mapRef.current.remove();mapRef.current=null;}
    };
  },[lat,lng,zoom]);
  return <div ref={containerRef} style={{width:"100%",height:"100%",background:"#e8ede0"}}/>;
}

