        {[["2025 Driver tax documents","tax"],["About your earnings","ae"],["Earnings FAQ","ef"],["Sharing your location","err"],["Earnings","err"]].map(([label,action],i)=><div key={i} onClick={()=>action==="ae"?goTo("aboutEarnings"):action==="tax"?goTo("taxModal"):action==="ef"?goTo("earningsFaq"):onErr()} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"15px 16px",borderBottom:i<4?"1px solid #F0F0F0":"none",cursor:"pointer"}}><span style={{fontSize:16,color:"#111"}}>{label}</span><span style={{color:BLUE,fontSize:18}}>›</span></div>)}
