function NavAppPicker({selected,onSelect,onClose}){
  const options=["Apple Maps","Leaflet"];
  return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.5)",zIndex:500,display:"flex",alignItems:"flex-end",justifyContent:"center"}}>
    <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:"20px 20px 0 0",width:"100%",maxWidth:430,paddingBottom:24}}>
      <div style={{display:"flex",alignItems:"center",padding:"18px 20px 8px"}}>
        <div onClick={onClose} style={{color:BLUE,fontSize:24,cursor:"pointer",width:30}}>✕</div>
        <div style={{flex:1,textAlign:"center",color:BLUE,fontWeight:700,fontSize:19,marginRight:30}}>Select default navigation app</div>
      </div>
      <div style={{display:"flex",gap:28,padding:"20px 24px 24px",justifyContent:"center"}}>
        {options.map(name=>(
          <div key={name} onClick={()=>{if(name==="Leaflet")onSelect(name);}} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:8,cursor:name==="Leaflet"?"pointer":"default",width:90,opacity:name==="Leaflet"?1:0.4}}>
            <div style={{width:88,height:88,borderRadius:20,background:"#EEEFF3",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 1px 4px rgba(0,0,0,0.12)",border:selected===name?`3px solid ${BLUE}`:"3px solid transparent",boxSizing:"border-box",padding:"0 8px",textAlign:"center"}}>
              <span style={{fontSize:15,fontWeight:700,color:BLUE}}>{name}</span>
            </div>
          </div>
        ))}
      </div>
      <div style={{borderTop:"1px solid #E5E7EB"}}/>
      <div onClick={onClose} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"18px 20px 0",cursor:"pointer"}}>
        <span style={{fontSize:17,color:"#9CA3AF",fontWeight:500}}>Save my choice</span>
        <span style={{color:BLUE,fontSize:20,fontWeight:700}}>✓</span>
      </div>
    </div>
  </div>;
}

export default function App(){
  const [nav,setNav]=useState("home");
  const [screen,setScreen]=useState("home");
  const [modal,setModal]=useState(null);
  const [tripsPopup,setTripsPopup]=useState(false);
  const [selectedTrip,setSelectedTrip]=useState(null);
  const [selectedWeek,setSelectedWeek]=useState(null);
  const [selectedDay,setSelectedDay]=useState(null);
  const [selectedIncentive,setSelectedIncentive]=useState(null);
  const [tripDetailCaller,setTripDetailCaller]=useState("trips");
  const [tripsScrollPos,setTripsScrollPos]=useState(0);
  const [tutStep,setTutStep]=useState(0);
  const [helpCaller,setHelpCaller]=useState("home");
  const [navApp,setNavApp]=useState("Leaflet");
  const NO_NAV=["offerTimes","tripDetail","earningsDetail","dayTrips","help","aboutEarnings","tutorial","taxModal","earningsFaq","driversLicense","account","personalDetails","nameDetail","emailDetail","phoneDetail","addressDetail","vehicleDetails","settings","incentivePrograms","incentiveHistory","incentiveDetail","inAppLanguage","commPrefs","troubleshooting","contractTerms","ndaTerms","rewardsTerms","certifications","metricsRewards","privacyPolicy","manageAccount"];
  function navTo(id){setNav(id);setScreen(id);if(id==="trips")setTripsPopup(true);}
  function goTo(id,data){
    if(id==="tripDetail")setTripDetailCaller(screen);
    setScreen(id);
    if(id==="tripDetail")setSelectedTrip(typeof data==="number"?TRIPS[data]:data);
    if(id==="earningsDetail")setSelectedWeek(data);
    if(id==="dayTrips")setSelectedDay(data);
    if(id==="incentiveDetail")setSelectedIncentive(data);
    if(id==="help")setHelpCaller(nav);
    if(id==="tutorial")setTutStep(typeof data==="number"?data:0);
  }
  function goBack(to){setScreen(to||nav);}
  function onErr(){setModal("err");}
  const showNav=!NO_NAV.includes(screen);
  return <div style={{width:"100%",maxWidth:430,height:"100vh",margin:"0 auto",position:"relative",overflow:"hidden",background:"#fff",fontFamily:"-apple-system,BlinkMacSystemFont,'Helvetica Neue',sans-serif"}}>
    {screen==="home"&&<HomeScreen onErr={onErr} goTo={goTo} navApp={navApp}/>}
    {screen==="offerTimes"&&<OfferTimesScreen goTo={goTo}/>}
    {screen==="trips"&&<TripsScreen goTo={goTo} showPopup={tripsPopup} setShowPopup={setTripsPopup} scrollPos={tripsScrollPos} onScrollPos={setTripsScrollPos}/>}
    {screen==="tripDetail"&&<TripDetailScreen trip={selectedTrip} goBack={()=>goBack(tripDetailCaller)}/>}
    {screen==="earnings"&&<EarningsScreen goTo={goTo} onHelp={()=>goTo("help")}/>}
    {screen==="earningsDetail"&&<EarningsDetailScreen week={selectedWeek} goBack={()=>goBack("earnings")} onHelp={()=>goTo("help")} goTo={goTo}/>}
    {screen==="dayTrips"&&<DayTripsScreen day={selectedDay} goBack={()=>goBack("earningsDetail")} goTo={goTo} onHelp={()=>goTo("help")}/>}
    {screen==="help"&&<HelpScreen goBack={()=>goBack(helpCaller)} goTo={goTo} onErr={onErr}/>}
    {screen==="earningsFaq"&&<EarningsFaqScreen goBack={()=>goBack("help")} onErr={onErr}/>}
    {screen==="taxModal"&&<div style={{display:"flex",flexDirection:"column",height:"100%",background:GRAY}}><Hdr title="Tax Documents" onBack={()=>goBack("help")} bg={BLUE}/><div style={{padding:20}}><div style={{background:"#fff",borderRadius:12,padding:20,textAlign:"center"}}><div style={{fontSize:34,marginBottom:10}}>📄</div><div style={{fontSize:17,fontWeight:700,color:"#111",marginBottom:8}}>2025 Tax Documents</div><div style={{fontSize:14,color:"#6B7280",lineHeight:1.55}}>No tax documents are available for 2025. You have no confirmed earnings on record for the 2025 tax year. If you believe this is an error, please contact Driver Support.</div></div></div></div>}
    {screen==="aboutEarnings"&&<AboutEarningsScreen goBack={()=>goBack("help")} startTut={(s)=>goTo("tutorial",s)}/>}
    {screen==="tutorial"&&<TutorialScreen step={tutStep} goBack={()=>goBack("aboutEarnings")} onNext={()=>{if(tutStep<TUT.length-1)setTutStep(tutStep+1);else goBack("aboutEarnings");}} onPrev={()=>setTutStep(tutStep-1)}/>}
    {screen==="driversLicense"&&<DriversLicenseScreen goBack={()=>goBack("more")}/>}
    {screen==="certifications"&&<CertificationsScreen goBack={()=>goBack("more")}/>}
    {screen==="incentivePrograms"&&<IncentiveProgramsScreen goBack={()=>goBack("more")} goTo={goTo}/>}
    {screen==="incentiveHistory"&&<IncentiveHistoryScreen goBack={()=>goBack("incentivePrograms")} goTo={goTo}/>}
    {screen==="incentiveDetail"&&<IncentiveDetailScreen entry={selectedIncentive} goBack={()=>goBack("incentiveHistory")}/>}
    {screen==="account"&&<AccountScreen goBack={()=>goBack("more")} setModal={setModal} goTo={goTo}/>}
    {screen==="personalDetails"&&<PersonalDetailsScreen goBack={()=>goBack("account")} setModal={setModal} goTo={goTo}/>}
    {screen==="nameDetail"&&<NameDetailScreen goBack={()=>goBack("personalDetails")} setModal={setModal}/>}
    {screen==="emailDetail"&&<EmailDetailScreen goBack={()=>goBack("personalDetails")} setModal={setModal}/>}
    {screen==="phoneDetail"&&<PhoneDetailScreen goBack={()=>goBack("personalDetails")} setModal={setModal}/>}
    {screen==="addressDetail"&&<AddressDetailScreen goBack={()=>goBack("personalDetails")} setModal={setModal}/>}
    {screen==="vehicleDetails"&&<VehicleDetailsScreen goBack={()=>goBack("more")} setModal={setModal}/>}
    {screen==="settings"&&<SettingsScreen goBack={()=>goBack("more")} setModal={setModal} goTo={goTo}/>}
    {screen==="inAppLanguage"&&<InAppLanguageScreen goBack={()=>goBack("settings")} setModal={setModal}/>}
    {screen==="commPrefs"&&<CommunicationsPreferencesScreen goBack={()=>goBack("settings")} setModal={setModal}/>}
    {screen==="troubleshooting"&&<TroubleshootingScreen goBack={()=>goBack("settings")} setModal={setModal}/>}
    {screen==="contractTerms"&&<SparkDriverContractScreen goBack={()=>goBack("settings")} setModal={setModal}/>}
    {screen==="ndaTerms"&&<NonDisclosureScreen goBack={()=>goBack("settings")} setModal={setModal}/>}
    {screen==="rewardsTerms"&&<RewardsTermsScreen goBack={()=>goBack("settings")}/>}
    {screen==="metricsRewards"&&<MetricsRewardsScreen goBack={()=>goBack("more")} onHelp={()=>goTo("help")}/>}
    {screen==="privacyPolicy"&&<PrivacyPolicyScreen goBack={()=>goBack("settings")}/>}
    {screen==="manageAccount"&&<ManageAccountScreen goBack={()=>goBack("settings")} setModal={setModal}/>}
    {screen==="notifications"&&<div style={{display:"flex",flexDirection:"column",height:"100%",background:"#F2F2F7"}}>
      <Hdr title="Notifications" bg={BLUE}/>
      <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",paddingBottom:80,gap:16}}>
        <svg width="80" height="80" viewBox="0 0 24 24" fill="none" stroke="#B0B8C1" strokeWidth="1.2" strokeLinecap="round" strokeLinejoin="round">
          <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/>
          <path d="M13.73 21a2 2 0 0 1-3.46 0"/>
          <line x1="2" y1="2" x2="4" y2="4" strokeWidth="1.4"/>
          <line x1="22" y1="2" x2="20" y2="4" strokeWidth="1.4"/>
          <line x1="12" y1="0" x2="12" y2="2.5" strokeWidth="1.4"/>
        </svg>
        <div style={{textAlign:"center"}}>
          <div style={{fontSize:17,fontWeight:700,color:"#1a1a1a",marginBottom:4}}>No Notifications</div>
          <div style={{fontSize:14,color:"#8E8E93"}}>{"You're all caught up."}</div>
        </div>
      </div>
    </div>}
    {screen==="more"&&<MoreScreen goTo={goTo} setModal={setModal} navApp={navApp}/>}
    {modal==="navApp"&&<NavAppPicker selected={navApp} onSelect={(a)=>{setNavApp(a);setModal(null);}} onClose={()=>setModal(null)}/>}
    {modal==="err"&&<div style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.5)",zIndex:2000,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}><div style={{background:"#fff",borderRadius:16,padding:"24px 20px",width:"100%",maxWidth:310,textAlign:"center"}}><div style={{fontSize:34,marginBottom:10}}>⚠️</div><div style={{fontSize:17,fontWeight:700,color:"#111",marginBottom:8}}>{"Something's Not Working"}</div><div style={{fontSize:14,color:"#6B7280",lineHeight:1.55,marginBottom:20}}>We are experiencing a technical issue. Please try again later.</div><button onClick={()=>setModal(null)} style={{background:BLUE,color:"#fff",border:"none",borderRadius:100,width:"100%",padding:14,fontSize:15,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>OK</button></div></div>}
    {modal==="testNotif"&&<div style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.5)",zIndex:2000,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}><div style={{background:"#fff",borderRadius:16,padding:"24px 20px",width:"100%",maxWidth:310,textAlign:"center"}}><div style={{fontSize:34,marginBottom:10}}>🔔</div><div style={{fontSize:17,fontWeight:700,color:"#111",marginBottom:8}}>This is a test notification</div><div style={{fontSize:14,color:"#6B7280",lineHeight:1.55,marginBottom:20}}>{"It looks like you're good to go."}</div><button onClick={()=>setModal(null)} style={{background:BLUE,color:"#fff",border:"none",borderRadius:100,width:"100%",padding:14,fontSize:15,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>OK</button></div></div>}
    {showNav&&<NavBar active={nav} onNav={navTo}/>}
  </div>;
}
